export type StepStateType = 'active' | 'success' | 'error' | 'disabled' | 'visited' | 'non-visited';
export type StepperDirectionType = 'vertical' | 'horizontal';
export type StepOrderMapType = Record<StepStateType, boolean>;
export interface StepType {
    /**
     * Идентификатор шага.
     */
    id: string;
    /**
     * Наименование шага.
     */
    label: string;
    /**
     * Верхний колонтитул шага.
     */
    signature?: string;
    /**
     * Статус шага - определяет форму и цвет иконки шага.
     */
    state?: StepStateType;
    /**
     * Состояние "активный" шага - определяет, какой шаг активен ("по которому был клик" - для нелинейного варианта отображения).
     */
    activated?: boolean;
    /**
     * Определяет отображение шага "в строку" / "в столбец".
     */
    direction?: StepperDirectionType;
}
export interface StepCommonProps extends StepType {
    /**
     * Порядковый номер шага
     */
    order?: number;
    /**
     * Событие клика по шагу
     */
    onClick?: (id: string) => void;
}
